import { Component } from '@angular/core';
import { MatTabsModule } from '@angular/material/tabs';
import { ActivatedRoute, Router, RouterOutlet } from '@angular/router';
import { MatIcon } from '@angular/material/icon';
import { CommonModule } from '@angular/common';
import { tabs } from '../master.utils';
import { MasterSignalService } from '../master.signal.service';

@Component({
  selector: 'app-master-tabs',
  standalone: true,
  imports: [MatTabsModule, RouterOutlet, MatIcon, CommonModule],
  templateUrl: './master-tabs.component.html',
  styleUrl: './master-tabs.component.css'
})
export class MasterTabsComponent {
  selectedTabIndex = sessionStorage.getItem("masterTabIndex") || 0;

  constructor(private router: Router, private route: ActivatedRoute, private mastersignal: MasterSignalService) {
    this.externalTabClick();
  }

  roleId = Number(sessionStorage.getItem('roleId'));

  tabs: any[] = this.roleId === 1 ? tabs : tabs.filter(tab => tab.title != "User Management");

  // Method to route to the selected tab
  onTabChange = (index: number) => {
    console.log("roleId", Number(this.roleId) === 1);
    this.selectedTabIndex = index;
    const selectedRoute = tabs[index].route;
    sessionStorage.setItem("masterTabIndex", String(index));
    sessionStorage.setItem("masterTab", tabs[index].title);
    this.router.navigate([selectedRoute]);
  }

  externalTabClick = () => {
    const indexOfTab = tabs.findIndex(item => item.title == sessionStorage.getItem("masterTab"))
    this.onTabChange(indexOfTab)
  }
}
